import{_ as t,o as a,c as o,a2 as s}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"Features","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/features.md","filePath":"en/guide/features.md","lastUpdated":1783223243000}'),r={name:"en/guide/features.md"};function i(n,e,d,c,l,h){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h1><p>Every CZero feature can be toggled independently in <code>config.json</code> and is triggered by the daemon on its own schedule. This page explains <strong>what each feature does, how it&#39;s triggered, and what safeguards apply</strong>.</p><h2 id="cache-cleaning" tabindex="-1">Cache cleaning <a class="header-anchor" href="#cache-cleaning" aria-label="Permalink to &quot;Cache cleaning&quot;">​</a></h2><p>Dedicated cleaners for frequently used apps (WeChat, QQ, Douyin), triggered at the frequency of <code>app_clean.detect_schedule</code>.</p><h3 id="checks-before-triggering" tabindex="-1">Checks before triggering <a class="header-anchor" href="#checks-before-triggering" aria-label="Permalink to &quot;Checks before triggering&quot;">​</a></h3><p>On each trigger, <code>check</code> first inspects the app&#39;s current state to avoid pointless or harmful cleaning:</p><ul><li><strong>Only cleans apps that should be cleaned</strong> — identifies the foreground app by reading <code>/dev/cpuset/top-app</code> and <code>dumpsys activity</code> (<code>ResumedActivity</code>), using <code>oom_score_adj</code> to pin down the foreground main process.</li><li><strong>Never cleans the foreground app</strong> — if an app is currently in use in the foreground, it&#39;s skipped this round so ongoing actions aren&#39;t disrupted.</li><li><strong>Game-foreground protection</strong> — a built-in list of common game packages; when a game is in the foreground, cleaning is skipped so gameplay isn&#39;t interrupted.</li></ul><h3 id="per-app-switches" tabindex="-1">Per-app switches <a class="header-anchor" href="#per-app-switches" aria-label="Permalink to &quot;Per-app switches&quot;">​</a></h3><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;wechat&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;enabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;enhanced&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><ul><li><code>enabled</code> — whether to clean this app.</li><li><code>enhanced</code> — <strong>enhanced mode</strong>. When on, cleaning is more thorough (wider scope); off by default for safety.</li></ul><h3 id="other-apps-cleaning" tabindex="-1">Other-apps cleaning <a class="header-anchor" href="#other-apps-cleaning" aria-label="Permalink to &quot;Other-apps cleaning&quot;">​</a></h3><p><code>app_clean.other</code> handles caches beyond the big three, run on its <code>schedule</code> (default daily 03:00).</p><h3 id="master-switch-temporal-barrier" tabindex="-1">Master switch &amp; temporal barrier <a class="header-anchor" href="#master-switch-temporal-barrier" aria-label="Permalink to &quot;Master switch &amp; temporal barrier&quot;">​</a></h3><ul><li>Governed by the master switch <code>general.auto_clean</code>.</li><li>Protected by <code>general.temporal_barrier_days</code> (the <strong>temporal barrier</strong>): only files older than N days are cleaned, protecting recent data; <code>0</code> disables it.</li></ul><h2 id="background-suppression" tabindex="-1">Background suppression <a class="header-anchor" href="#background-suppression" aria-label="Permalink to &quot;Background suppression&quot;">​</a></h2><p>At the frequency of <code>suppress.detect_schedule</code>, periodically suppresses target apps running in the background.</p><p>How it works: it walks <code>/proc</code>, finds the target apps&#39; background processes, and terminates them (<code>SIGKILL</code>), freeing memory and reducing background drain. Key safeguards:</p><ul><li><strong>Never touches the foreground app</strong> — an app currently in the foreground is never suppressed.</li><li><strong>No suppression if the foreground is unknown</strong> — if this round can&#39;t determine the foreground app, it&#39;s skipped to avoid collateral damage.</li><li>Suppression counts are recorded in the stats (<code>suppress</code> in <code>basis.prop</code>).</li></ul><h2 id="f2fs-garbage-collection" tabindex="-1">F2FS garbage collection <a class="header-anchor" href="#f2fs-garbage-collection" aria-label="Permalink to &quot;F2FS garbage collection&quot;">​</a></h2><p>Monitors the F2FS dirty-segment count and runs garbage collection (GC) when it exceeds a threshold. For safety, GC waits for the screen to turn off before running and caps its runtime.</p><table tabindex="0"><thead><tr><th>Field</th><th>Meaning</th></tr></thead><tbody><tr><td><code>dirty_threshold</code></td><td>GC triggers when dirty segments exceed this (must be greater than <code>clean_threshold</code>)</td></tr><tr><td><code>clean_threshold</code></td><td>Considered done and stops when dirty segments drop below this</td></tr><tr><td><code>wait_screen_off_timeout</code></td><td>Timeout (seconds) waiting for screen-off; if still on, this round is abandoned</td></tr><tr><td><code>max_runtime_sec</code></td><td>Max runtime (seconds) for a single GC run; force-stopped when reached</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Why wait for screen-off</p><p>F2FS GC is disk-intensive; running it while the screen is off and the device is idle avoids affecting foreground responsiveness.</p></div><blockquote><p>GC requires an F2FS <code>/data</code> partition. On non-F2FS devices, set <code>gc.enabled</code> to <code>false</code>; everything else works regardless.</p></blockquote><h2 id="empty-folder-cleanup" tabindex="-1">Empty-folder cleanup <a class="header-anchor" href="#empty-folder-cleanup" aria-label="Permalink to &quot;Empty-folder cleanup&quot;">​</a></h2><p>On the <code>empty_folder.schedule</code> (default daily 04:00), sweeps away leftover empty directories. The scope is defined by <code>list/Emptyfolder/directories.prop</code> and constrained by the whitelist <code>emptyfolder_white.prop</code>.</p><h2 id="custom-path-cleaning" tabindex="-1">Custom-path cleaning <a class="header-anchor" href="#custom-path-cleaning" aria-label="Permalink to &quot;Custom-path cleaning&quot;">​</a></h2><p>Beyond the built-in rules, you can declare your own paths, swept by the daily job:</p><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>list/clean_paths.prop</code></td><td>List of custom paths to clean</td></tr><tr><td><code>list/clean_whitelist.prop</code></td><td>Cleaning whitelist (paths protected from cleaning)</td></tr></tbody></table><p>These lists can be managed via the CZeroX rule editor and are inherited across reinstalls.</p><h2 id="stats-logging" tabindex="-1">Stats &amp; logging <a class="header-anchor" href="#stats-logging" aria-label="Permalink to &quot;Stats &amp; logging&quot;">​</a></h2><ul><li><p><strong>Stats</strong> — per-app cleaning counts and suppression counts are recorded in <code>basis/basis.prop</code>; the CZeroX home page shows today&#39;s and total figures. The <code>zero</code> job resets the day&#39;s counters at 00:00.</p></li><li><p><strong>Logging</strong> — with <code>general.log</code> on, all components write to a single daily log <code>log/&lt;YYYY-MM-DD&gt;.log</code>, each line tagged with its source:</p><table tabindex="0"><thead><tr><th>Tag</th><th>Source</th></tr></thead><tbody><tr><td><code>[定时]</code></td><td>Scheduling daemon</td></tr><tr><td><code>[检测]</code></td><td>Foreground detection</td></tr><tr><td><code>[微信]</code> <code>[QQ]</code> <code>[抖音]</code></td><td>Per-app cleaning</td></tr><tr><td><code>[压制]</code></td><td>Background suppression</td></tr><tr><td><code>[GC]</code></td><td>F2FS garbage collection</td></tr><tr><td><code>[空文件夹]</code></td><td>Empty-folder cleanup</td></tr><tr><td><code>[自定义]</code></td><td>Custom-path cleaning</td></tr></tbody></table><p>Only today&#39;s log is kept (the <code>zero</code> job deletes non-today log files).</p></li></ul><p>Both are off by default and can be toggled at any time.</p><h2 id="dynamic-island-notifications" tabindex="-1">Dynamic Island notifications <a class="header-anchor" href="#dynamic-island-notifications" aria-label="Permalink to &quot;Dynamic Island notifications&quot;">​</a></h2><p>On start and finish, cleaners can broadcast events to CZeroX (<code>CleanEventReceiver</code>) to show progress / result notifications (including the Dynamic Island). This can be disabled via the environment variable <code>CZERO_NO_NOTIFY=1</code>.</p>',34)])])}const u=t(r,[["render",i]]);export{g as __pageData,u as default};
